  /// This allows you to tune a container's memory swappiness behavior. A
  /// <code>swappiness</code> value of <code>0</code> will cause swapping to not
  /// happen unless absolutely necessary. A <code>swappiness</code> value of
  /// <code>100</code> will cause pages to be swapped very aggressively. Accepted
  /// values are whole numbers between <code>0</code> and <code>100</code>. If the
  /// <code>swappiness</code> parameter is not specified, a default value of
  /// <code>60</code> is used. If a value is not specified for
  /// <code>maxSwap</code> then this parameter is ignored. This parameter maps to
  /// the <code>--memory-swappiness</code> option to docker run.
  /// <note>
  /// If you're using tasks that use the Fargate launch type, the
  /// <code>swappiness</code> parameter isn't supported.
  ///
  /// If you're using tasks on Amazon Linux 2023 the <code>swappiness</code>
  /// parameter isn't supported.
  /// </note>
  final int? swappiness;

  /// The container path, mount options, and size (in MiB) of the tmpfs mount.
  /// This parameter maps to the <code>--tmpfs</code> option to docker run.
  final List<Tmpfs>? tmpfs;

  LinuxParameters({
    this.capabilities,
    this.devices,
    this.initProcessEnabled,
    this.maxSwap,
    this.sharedMemorySize,
    this.swappiness,
    this.tmpfs,
  });

  factory LinuxParameters.fromJson(Map<String, dynamic> json) {
    return LinuxParameters(
      capabilities: json['capabilities'] != null
          ? KernelCapabilities.fromJson(
              json['capabilities'] as Map<String, dynamic>)
          : null,
      devices: (json['devices'] as List?)
          ?.nonNulls
          .map((e) => Device.fromJson(e as Map<String, dynamic>))
          .toList(),
      initProcessEnabled: json['initProcessEnabled'] as bool?,
      maxSwap: json['maxSwap'] as int?,
      sharedMemorySize: json['sharedMemorySize'] as int?,
      swappiness: json['swappiness'] as int?,
      tmpfs: (json['tmpfs'] as List?)
          ?.nonNulls
          .map((e) => Tmpfs.fromJson(e as Map<String, dynamic>))
          .toList(),
    );
  }

  Map<String, dynamic> toJson() {
    final capabilities = this.capabilities;
    final devices = this.devices;
    final initProcessEnabled = this.initProcessEnabled;
    final maxSwap = this.maxSwap;
    final sharedMemorySize = this.sharedMemorySize;
    final swappiness = this.swappiness;
    final tmpfs = this.tmpfs;
    return {
      if (capabilities != null) 'capabilities': capabilities,
      if (devices != null) 'devices': devices,
      if (initProcessEnabled != null) 'initProcessEnabled': initProcessEnabled,
      if (maxSwap != null) 'maxSwap': maxSwap,
      if (sharedMemorySize != null) 'sharedMemorySize': sharedMemorySize,
      if (swappiness != null) 'swappiness': swappiness,
      if (tmpfs != null) 'tmpfs': tmpfs,
    };
  }
}

/// @nodoc
class VersionConsistency {
  static const enabled = VersionConsistency._('enabled');
  static const disabled = VersionConsistency._('disabled');

  final String value;

  const VersionConsistency._(this.value);

  static const values = [enabled, disabled];

  static VersionConsistency fromString(String value) =>
      values.firstWhere((e) => e.value == value,
          orElse: () => VersionConsistency._(value));

  @override
  bool operator ==(other) =>
      other is VersionConsistency && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

/// The log configuration for the container. This parameter maps to
/// <code>LogConfig</code> in the docker container create command and the
/// <code>--log-driver</code> option to docker run.
///
/// By default, containers use the same logging driver that the Docker daemon
/// uses. However, the container might use a different logging driver than the
/// Docker daemon by specifying a log driver configuration in the container
/// definition.
///
/// Understand the following when specifying a log configuration for your
/// containers.
///
/// <ul>
/// <li>
/// Amazon ECS currently supports a subset of the logging drivers available to
/// the Docker daemon. Additional log drivers may be available in future
/// releases of the Amazon ECS container agent.
///
/// For tasks on Fargate, the supported log drivers are <code>awslogs</code>,
/// <code>splunk</code>, and <code>awsfirelens</code>.
///
/// For tasks hosted on Amazon EC2 instances, the supported log drivers are
/// <code>awslogs</code>, <code>fluentd</code>, <code>gelf</code>,
/// <code>json-file</code>, <code>journald</code>,<code>syslog</code>,
/// <code>splunk</code>, and <code>awsfirelens</code>.
/// </li>
/// <li>
/// This parameter requires version 1.18 of the Docker Remote API or greater on
/// your container instance.
/// </li>
/// <li>
/// For tasks that are hosted on Amazon EC2 instances, the Amazon ECS container
/// agent must register the available logging drivers with the
/// <code>ECS_AVAILABLE_LOGGING_DRIVERS</code> environment variable before
/// containers placed on that instance can use these log configuration options.
/// For more information, see <a
/// href="https://docs.aws.amazon.com/AmazonECS/latest/developerguide/ecs-agent-config.html">Amazon
/// ECS container agent configuration</a> in the <i>Amazon Elastic Container
/// Service Developer Guide</i>.
/// </li>
/// <li>
/// For tasks that are on Fargate, because you don't have access to the
/// underlying infrastructure your tasks are hosted on, any additional software
/// needed must be installed outside of the task. For example, the Fluentd
/// output aggregators or a remote host running Logstash to send Gelf logs to.
/// </li>
/// </ul>
///
/// @nodoc
class LogConfiguration {
  /// The log driver to use for the container.
  ///
  /// For tasks on Fargate, the supported log drivers are <code>awslogs</code>,
  /// <code>splunk</code>, and <code>awsfirelens</code>.
  ///
  /// For tasks hosted on Amazon EC2 instances, the supported log drivers are
  /// <code>awslogs</code>, <code>fluentd</code>, <code>gelf</code>,
  /// <code>json-file</code>, <code>journald</code>, <code>syslog</code>,
  /// <code>splunk</code>, and <code>awsfirelens</code>.
  ///
  /// For more information about using the <code>awslogs</code> log driver, see <a
  /// href="https://docs.aws.amazon.com/AmazonECS/latest/developerguide/using_awslogs.html">Send
  /// Amazon ECS logs to CloudWatch</a> in the <i>Amazon Elastic Container Service
  /// Developer Guide</i>.
  ///
  /// For more information about using the <code>awsfirelens</code> log driver,
  /// see <a
  /// href="https://docs.aws.amazon.com/AmazonECS/latest/developerguide/using_firelens.html">Send
  /// Amazon ECS logs to an Amazon Web Services service or Amazon Web Services
  /// Partner</a>.
  /// <note>
  /// If you have a custom driver that isn't listed, you can fork the Amazon ECS
  /// container agent project that's <a
  /// href="https://github.com/aws/amazon-ecs-agent">available on GitHub</a> and
  /// customize it to work with that driver. We encourage you to submit pull
  /// requests for changes that you would like to have included. However, we don't
  /// currently provide support for running modified copies of this software.
  /// </note>
  final LogDriver logDriver;

  /// The configuration options to send to the log driver.
  ///
  /// The options you can specify depend on the log driver. Some of the options
  /// you can specify when you use the <code>awslogs</code> log driver to route
  /// logs to Amazon CloudWatch include the following:
  /// <dl> <dt>awslogs-create-group</dt> <dd>
  /// Required: No
  ///
  /// Specify whether you want the log group to be created automatically. If this
  /// option isn't specified, it defaults to <code>false</code>.
  /// <note>
  /// Your IAM policy must include the <code>logs:CreateLogGroup</code> permission
  /// before you attempt to use <code>awslogs-create-group</code>.
  /// </note> </dd> <dt>awslogs-region</dt> <dd>
  /// Required: Yes
  ///
  /// Specify the Amazon Web Services Region that the <code>awslogs</code> log
  /// driver is to send your Docker logs to. You can choose to send all of your
  /// logs from clusters in different Regions to a single region in CloudWatch
  /// Logs. This is so that they're all visible in one location. Otherwise, you
  /// can separate them by Region for more granularity. Make sure that the
  /// specified log group exists in the Region that you specify with this option.
  /// </dd> <dt>awslogs-group</dt> <dd>
  /// Required: Yes
  ///
  /// Make sure to specify a log group that the <code>awslogs</code> log driver
  /// sends its log streams to.
  /// </dd> <dt>awslogs-stream-prefix</dt> <dd>
  /// Required: Yes, when using Fargate.Optional when using EC2.
  ///
  /// Use the <code>awslogs-stream-prefix</code> option to associate a log stream
  /// with the specified prefix, the container name, and the ID of the Amazon ECS
  /// task that the container belongs to. If you specify a prefix with this
  /// option, then the log stream takes the format
  /// <code>prefix-name/container-name/ecs-task-id</code>.
  ///
  /// If you don't specify a prefix with this option, then the log stream is named
  /// after the container ID that's assigned by the Docker daemon on the container
  /// instance. Because it's difficult to trace logs back to the container that
  /// sent them with just the Docker container ID (which is only available on the
  /// container instance), we recommend that you specify a prefix with this
  /// option.
  ///
  /// For Amazon ECS services, you can use the service name as the prefix. Doing
  /// so, you can trace log streams to the service that the container belongs to,
  /// the name of the container that sent them, and the ID of the task that the
  /// container belongs to.
  ///
  /// You must specify a stream-prefix for your logs to have your logs appear in
  /// the Log pane when using the Amazon ECS console.
  /// </dd> <dt>awslogs-datetime-format</dt> <dd>
  /// Required: No
  ///
  /// This option defines a multiline start pattern in Python
  /// <code>strftime</code> format. A log message consists of a line that matches
  /// the pattern and any following lines that don’t match the pattern. The
  /// matched line is the delimiter between log messages.
  ///
  /// One example of a use case for using this format is for parsing output such
  /// as a stack dump, which might otherwise be logged in multiple entries. The
  /// correct pattern allows it to be captured in a single entry.
  ///
  /// For more information, see <a
  /// href="https://docs.docker.com/config/containers/logging/awslogs/#awslogs-datetime-format">awslogs-datetime-format</a>.
  ///
  /// You cannot configure both the <code>awslogs-datetime-format</code> and
  /// <code>awslogs-multiline-pattern</code> options.
  /// <note>
  /// Multiline logging performs regular expression parsing and matching of all
  /// log messages. This might have a negative impact on logging performance.
  /// </note> </dd> <dt>awslogs-multiline-pattern</dt> <dd>
  /// Required: No
  ///
  /// This option defines a multiline start pattern that uses a regular
  /// expression. A log message consists of a line that matches the pattern and
  /// any following lines that don’t match the pattern. The matched line is the
  /// delimiter between log messages.
  ///
  /// For more information, see <a
  /// href="https://docs.docker.com/config/containers/logging/awslogs/#awslogs-multiline-pattern">awslogs-multiline-pattern</a>.
  ///
  /// This option is ignored if <code>awslogs-datetime-format</code> is also
  /// configured.
  ///
  /// You cannot configure both the <code>awslogs-datetime-format</code> and
  /// <code>awslogs-multiline-pattern</code> options.
  /// <note>
  /// Multiline logging performs regular expression parsing and matching of all
  /// log messages. This might have a negative impact on logging performance.
  /// </note> </dd> </dl>
  /// The following options apply to all supported log drivers.
  /// <dl> <dt>mode</dt> <dd>
  /// Required: No
  ///
  /// Valid values: <code>non-blocking</code> | <code>blocking</code>
  ///
  /// This option defines the delivery mode of log messages from the container to
  /// the log driver specified using <code>logDriver</code>. The delivery mode you
  /// choose affects application availability when the flow of logs from container
  /// is interrupted.
  ///
  /// If you use the <code>blocking</code> mode and the flow of logs is
  /// interrupted, calls from container code to write to the <code>stdout</code>
  /// and <code>stderr</code> streams will block. The logging thread of the
  /// application will block as a result. This may cause the application to become
  /// unresponsive and lead to container healthcheck failure.
  ///
  /// If you use the <code>non-blocking</code> mode, the container's logs are
  /// instead stored in an in-memory intermediate buffer configured with the
  /// <code>max-buffer-size</code> option. This prevents the application from
  /// becoming unresponsive when logs cannot be sent. We recommend using this mode
  /// if you want to ensure service availability and are okay with some log loss.
  /// For more information, see <a
  /// href="http://aws.amazon.com/blogs/containers/preventing-log-loss-with-non-blocking-mode-in-the-awslogs-container-log-driver/">Preventing
  /// log loss with non-blocking mode in the <code>awslogs</code> container log
  /// driver</a>.
  ///
  /// You can set a default <code>mode</code> for all containers in a specific
  /// Amazon Web Services Region by using the <code>defaultLogDriverMode</code>
  /// account setting. If you don't specify the <code>mode</code> option or
  /// configure the account setting, Amazon ECS will default to the
  /// <code>non-blocking</code> mode. For more information about the account
  /// setting, see <a
  /// href="https://docs.aws.amazon.com/AmazonECS/latest/developerguide/ecs-account-settings.html#default-log-driver-mode">Default
  /// log driver mode</a> in the <i>Amazon Elastic Container Service Developer
  /// Guide</i>.
  /// <note>
  /// On June 25, 2025, Amazon ECS changed the default log driver mode from
  /// <code>blocking</code> to <code>non-blocking</code> to prioritize task
  /// availability over logging. To continue using the <code>blocking</code> mode
  /// after this change, do one of the following:
  ///
  /// <ul>
  /// <li>
  /// Set the <code>mode</code> option in your container definition's
  /// <code>logConfiguration</code> as <code>blocking</code>.
  /// </li>
  /// <li>
  /// Set the <code>defaultLogDriverMode</code> account setting to
  /// <code>blocking</code>.
  /// </li>
  /// </ul> </note> </dd> <dt>max-buffer-size</dt> <dd>
  /// Required: No
  ///
  /// Default value: <code>10m</code>
  ///
  /// When <code>non-blocking</code> mode is used, the
  /// <code>max-buffer-size</code> log option controls the size of the buffer
  /// that's used for intermediate message storage. Make sure to specify an
  /// adequate buffer size based on your application. When the buffer fills up,
  /// further logs cannot be stored. Logs that cannot be stored are lost.
  /// </dd> </dl>
  /// To route logs using the <code>splunk</code> log router, you need to specify
  /// a <code>splunk-token</code> and a <code>splunk-url</code>.
  ///
  /// When you use the <code>awsfirelens</code> log router to route logs to an
  /// Amazon Web Services Service or Amazon Web Services Partner Network
  /// destination for log storage and analytics, you can set the
  /// <code>log-driver-buffer-limit</code> option to limit the number of events
  /// that are buffered in memory, before being sent to the log router container.
  /// It can help to resolve potential log loss issue because high throughput
  /// might result in memory running out for the buffer inside of Docker.
  ///
  /// Other options you can specify when using <code>awsfirelens</code> to route
  /// logs depend on the destination. When you export logs to Amazon Data
  /// Firehose, you can specify the Amazon Web Services Region with
  /// <code>region</code> and a name for the log stream with
  /// <code>delivery_stream</code>.
  ///
  /// When you export logs to Amazon Kinesis Data Streams, you can specify an
  /// Amazon Web Services Region with <code>region</code> and a data stream name
  /// with <code>stream</code>.
  ///
  /// When you export logs to Amazon OpenSearch Service, you can specify options
  /// like <code>Name</code>, <code>Host</code> (OpenSearch Service endpoint
  /// without protocol), <code>Port</code>, <code>Index</code>, <code>Type</code>,
  /// <code>Aws_auth</code>, <code>Aws_region</code>,
  /// <code>Suppress_Type_Name</code>, and <code>tls</code>. For more information,
  /// see <a
  /// href="http://aws.amazon.com/blogs/containers/under-the-hood-firelens-for-amazon-ecs-tasks/">Under
  /// the hood: FireLens for Amazon ECS Tasks</a>.
  ///
  /// When you export logs to Amazon S3, you can specify the bucket using the
  /// <code>bucket</code> option. You can also specify <code>region</code>,
  /// <code>total_file_size</code>, <code>upload_timeout</code>, and
  /// <code>use_put_object</code> as options.
  ///
  /// This parameter requires version 1.19 of the Docker Remote API or greater on
  /// your container instance. To check the Docker Remote API version on your
  /// container instance, log in to your container instance and run the following
  /// command: <code>sudo docker version --format '{{.Server.APIVersion}}'</code>
  final Map<String, String>? options;

  /// The secrets to pass to the log configuration. For more information, see <a
  /// href="https://docs.aws.amazon.com/AmazonECS/latest/developerguide/specifying-sensitive-data.html">Specifying
  /// sensitive data</a> in the <i>Amazon Elastic Container Service Developer
  /// Guide</i>.
  final List<Secret>? secretOptions;

  LogConfiguration({
    required this.logDriver,
    this.options,
    this.secretOptions,
  });

  factory LogConfiguration.fromJson(Map<String, dynamic> json) {
    return LogConfiguration(
      logDriver: LogDriver.fromString((json['logDriver'] as String?) ?? ''),
      options: (json['options'] as Map<String, dynamic>?)
          ?.map((k, e) => MapEntry(k, e as String)),
      secretOptions: (json['secretOptions'] as List?)
          ?.nonNulls
          .map((e) => Secret.fromJson(e as Map<String, dynamic>))
          .toList(),
    );
  }

  Map<String, dynamic> toJson() {
    final logDriver = this.logDriver;
    final options = this.options;
    final secretOptions = this.secretOptions;
    return {
      'logDriver': logDriver.value,
      if (options != null) 'options': options,
      if (secretOptions != null) 'secretOptions': secretOptions,
    };
  }
}

/// An object representing a container health check. Health check parameters
/// that are specified in a container definition override any Docker health
/// checks that exist in the container image (such as those specified in a
/// parent image or from the image's Dockerfile). This configuration maps to the
/// <code>HEALTHCHECK</code> parameter of docker run.
/// <note>
/// The Amazon ECS container agent only monitors and reports on the health
/// checks specified in the task definition. Amazon ECS does not monitor Docker
/// health checks that are embedded in a container image and not specified in
/// the container definition. Health check parameters that are specified in a
/// container definition override any Docker health checks that exist in the
/// container image.
/// </note>
/// You can view the health status of both individual containers and a task with
/// the DescribeTasks API operation or when viewing the task details in the
/// console.
///
/// The health check is designed to make sure that your containers survive agent
/// restarts, upgrades, or temporary unavailability.
///
/// Amazon ECS performs health checks on containers with the default that
/// launched the container instance or the task.
///
/// The following describes the possible <code>healthStatus</code> values for a
/// container:
///
/// <ul>
/// <li>
/// <code>HEALTHY</code>-The container health check has passed successfully.
/// </li>
/// <li>
/// <code>UNHEALTHY</code>-The container health check has failed.
/// </li>
/// <li>
/// <code>UNKNOWN</code>-The container health check is being evaluated, there's
/// no container health check defined, or Amazon ECS doesn't have the health
/// status of the container.
/// </li>
/// </ul>
/// The following describes the possible <code>healthStatus</code> values based
/// on the container health checker status of essential containers in the task
/// with the following priority order (high to low):
///
/// <ul>
/// <li>
/// <code>UNHEALTHY</code>-One or more essential containers have failed their
/// health check.
/// </li>
/// <li>
/// <code>UNKNOWN</code>-Any essential container running within the task is in
/// an <code>UNKNOWN</code> state and no other essential containers have an
/// <code>UNHEALTHY</code> state.
/// </li>
/// <li>
/// <code>HEALTHY</code>-All essential containers within the task have passed
/// their health checks.
/// </li>
/// </ul>
/// Consider the following task health example with 2 containers.
///
/// <ul>
/// <li>
/// If Container1 is <code>UNHEALTHY</code> and Container2 is
/// <code>UNKNOWN</code>, the task health is <code>UNHEALTHY</code>.
/// </li>
/// <li>
/// If Container1 is <code>UNHEALTHY</code> and Container2 is
/// <code>HEALTHY</code>, the task health is <code>UNHEALTHY</code>.
/// </li>
/// <li>
/// If Container1 is <code>HEALTHY</code> and Container2 is
/// <code>UNKNOWN</code>, the task health is <code>UNKNOWN</code>.
/// </li>
/// <li>
/// If Container1 is <code>HEALTHY</code> and Container2 is
/// <code>HEALTHY</code>, the task health is <code>HEALTHY</code>.
/// </li>
/// </ul>
/// Consider the following task health example with 3 containers.
///
/// <ul>
/// <li>
/// If Container1 is <code>UNHEALTHY</code> and Container2 is
/// <code>UNKNOWN</code>, and Container3 is <code>UNKNOWN</code>, the task
/// health is <code>UNHEALTHY</code>.
/// </li>
/// <li>
/// If Container1 is <code>UNHEALTHY</code> and Container2 is
/// <code>UNKNOWN</code>, and Container3 is <code>HEALTHY</code>, the task
/// health is <code>UNHEALTHY</code>.
/// </li>
/// <li>
/// If Container1 is <code>UNHEALTHY</code> and Container2 is
/// <code>HEALTHY</code>, and Container3 is <code>HEALTHY</code>, the task
/// health is <code>UNHEALTHY</code>.
/// </li>
/// <li>
/// If Container1 is <code>HEALTHY</code> and Container2 is
/// <code>UNKNOWN</code>, and Container3 is <code>HEALTHY</code>, the task
/// health is <code>UNKNOWN</code>.
/// </li>
/// <li>
/// If Container1 is <code>HEALTHY</code> and Container2 is
/// <code>UNKNOWN</code>, and Container3 is <code>UNKNOWN</code>, the task
/// health is <code>UNKNOWN</code>.
/// </li>
/// <li>
/// If Container1 is <code>HEALTHY</code> and Container2 is
/// <code>HEALTHY</code>, and Container3 is <code>HEALTHY</code>, the task
/// health is <code>HEALTHY</code>.
/// </li>
/// </ul>
/// If a task is run manually, and not as part of a service, the task will
/// continue its lifecycle regardless of its health status. For tasks that are
/// part of a service, if the task reports as unhealthy then the task will be
/// stopped and the service scheduler will replace it.
///
/// When a container health check fails for a task that is part of a service,
/// the following process occurs:
/// <ol>
/// <li>
/// The task is marked as <code>UNHEALTHY</code>.
/// </li>
/// <li>
/// The unhealthy task will be stopped, and during the stopping process, it will
/// go through the following states:
///
/// <ul>
/// <li>
/// <code>DEACTIVATING</code> - In this state, Amazon ECS performs additional
/// steps before stopping the task. For example, for tasks that are part of
/// services configured to use Elastic Load Balancing target groups, target
/// groups will be deregistered in this state.
/// </li>
/// <li>
/// <code>STOPPING</code> - The task is in the process of being stopped.
/// </li>
/// <li>
/// <code>DEPROVISIONING</code> - Resources associated with the task are being
/// cleaned up.
/// </li>
/// <li>
/// <code>STOPPED</code> - The task has been completely stopped.
/// </li>
/// </ul> </li>
/// <li>
/// After the old task stops, a new task will be launched to ensure service
/// operation, and the new task will go through the following lifecycle:
///
/// <ul>
/// <li>
/// <code>PROVISIONING</code> - Resources required for the task are being
/// provisioned.
/// </li>
/// <li>
/// <code>PENDING</code> - The task is waiting to be placed on a container
/// instance.
/// </li>
/// <li>
/// <code>ACTIVATING</code> - In this state, Amazon ECS pulls container images,
/// creates containers, configures task networking, registers load balancer
/// target groups, and configures service discovery status.
/// </li>
/// <li>
/// <code>RUNNING</code> - The task is running and performing its work.
/// </li>
/// </ul> </li> </ol>
/// For more detailed information about task lifecycle states, see <a
/// href="https://docs.aws.amazon.com/AmazonECS/latest/developerguide/task-lifecycle-explanation.html">Task
/// lifecycle</a> in the <i>Amazon Elastic Container Service Developer
/// Guide</i>.
///
/// The following are notes about container health check support:
///
/// <ul>
/// <li>
/// If the Amazon ECS container agent becomes disconnected from the Amazon ECS
/// service, this won't cause a container to transition to an
/// <code>UNHEALTHY</code> status. This is by design, to ensure that containers
/// remain running during agent restarts or temporary unavailability. The health
/// check status is the "last heard from" response from the Amazon ECS agent, so
/// if the container was considered <code>HEALTHY</code> prior to the
/// disconnect, that status will remain until the agent reconnects and another
/// health check occurs. There are no assumptions made about the status of the
/// container health checks.
/// </li>
/// <li>
/// Container health checks require version <code>1.17.0</code> or greater of
/// the Amazon ECS container agent. For more information, see <a
/// href="https://docs.aws.amazon.com/AmazonECS/latest/developerguide/ecs-agent-update.html">Updating
/// the Amazon ECS container agent</a>.
/// </li>
/// <li>
/// Container health checks are supported for Fargate tasks if you're using
/// platform version <code>1.1.0</code> or greater. For more information, see <a
/// href="https://docs.aws.amazon.com/AmazonECS/latest/developerguide/platform_versions.html">Fargate
/// platform versions</a>.
/// </li>
/// <li>
/// Container health checks aren't supported for tasks that are part of a
